interface x_bus #(ADDR_WIDTH=32) (input wire clk);
logic [ADDR_WIDTH-1:0] address;
task write_reg(input string name, input integer addr, input integer value);
begin
  @(posedge clk);
  address = ADDR_WIDTH'(addr);
end
endtask
endinterface

task write_reg(input string name, input integer addr, input integer value);
integer timeout = 256;
begin
  @(posedge clk);
  timeout = 256;
  write = 1;
  while (!write_done) begin
    @(posedge clk);
    if (timeout > 0) timeout = timeout - 1;
    else break;
  end
end
endtask

task write_reg(input string name, input integer addr, input integer value);
while (!write_done) begin
  @(posedge clk);
  write = 0;
end
endtask

interface x_bus #(ADDR_WIDTH=32) (input wire clk);
logic [ADDR_WIDTH-1:0] address;
modport slave (input address, output read_data);
modport master (input read_data, output address);
task write_reg(input string name, input integer addr, input integer value);
begin
  @(posedge clk);
end
endtask
endinterface
